function Get-ParsecIngredientOperations {
    return @{ capture = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) Get-ParsecProcessCaptureResult -Arguments $Arguments }; apply = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $process = if ($Arguments.ContainsKey('process_id')) { Get-Process -Id ([int] $Arguments.process_id) -ErrorAction SilentlyContinue } elseif ($Arguments.ContainsKey('process_name')) { @(Get-Process -Name $Arguments.process_name -ErrorAction SilentlyContinue) | Select-Object -First 1 } else { $null }; if ($null -eq $process) { return New-ParsecResult -Status 'Succeeded' -Message 'Process was already stopped.' }; Stop-Process -Id $process.Id -ErrorAction SilentlyContinue; New-ParsecResult -Status 'Succeeded' -Message "Stopped process id '$($process.Id)'." }; verify = { param($Arguments, $ExecutionResult, $StateRoot, $RunState, $Definition) $process = if ($Arguments.ContainsKey('process_id')) { Get-Process -Id ([int] $Arguments.process_id) -ErrorAction SilentlyContinue } elseif ($Arguments.ContainsKey('process_name')) { @(Get-Process -Name $Arguments.process_name -ErrorAction SilentlyContinue) | Select-Object -First 1 } else { $null }; if ($null -eq $process) { return New-ParsecResult -Status 'Succeeded' -Message 'Process is stopped.' }; New-ParsecResult -Status 'Failed' -Message 'Process is still running.' -Observed @{ process_id = [int] $process.Id; process_name = [string] $process.ProcessName } } }
}